'use client';

import { motion, AnimatePresence } from 'framer-motion';
import { useEffect, useMemo, useState } from 'react';
import dynamic from 'next/dynamic';
import Link from 'next/link';
import { Plus } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/context/AuthContext';
import { EventCategory } from '@/types';
import { fetchEvents } from '@/api/events/events';
import { deleteEvent } from '@/api/events';
import { Card } from '@/components/ui/Card';
import { StatCard } from '@/components/ui/StatCard';
import { Activity, Check, X } from 'lucide-react';

const Loading = dynamic(() => import('@/components/ui/Loading').then((m) => m.Loading), { ssr: false });
const NotFound = dynamic(() => import('@/components/ui/NotFound'));
const EventCard = dynamic(() => import('@/components/ui/EventCard'));
const Pagination = dynamic(() => import('@/components/ui/Pagination'));
const DeleteConfirmationDialog = dynamic(
  () => import('@/components/dialog/DeleteConfirmationDialog'),
  { ssr: false }
);

type FilterType = 'all' | 'upcoming' | 'past';

const HostDashboard = () => {
  const { toast } = useToast();
  const { token } = useAuth();

  const [events, setEvents] = useState<EventCategory[]>([]);
  const [loading, setLoading] = useState<boolean>(false);

  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [currentPage, setCurrentPage] = useState<number>(1);
  const [totalPages, setTotalPages] = useState<number>(0);
  const [eventsPerPage] = useState<number>(8);

  const [selectedEvent, setSelectedEvent] = useState<EventCategory | null>(null);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);

  useEffect(() => {
    if (!token) return;
    fetchEvents({
      token,
      currentPage,
      eventsPerPage,
      activeFilter,
      role: 'host',
      toast,
      setLoading,
    }).then((data) => {
      setEvents(Array.isArray(data?.events) ? data.events : []);
      setTotalPages(data?.totalPages || 0);
    });
  }, [token, currentPage, activeFilter, eventsPerPage, toast]);

  const stats = useMemo(() => {
    const total = events.length;
    const approved = events.filter((e) => (e.status as any) === 'approved').length;
    const rejected = events.filter((e) => (e.status as any) === 'rejected').length;
    return { total, approved, rejected };
  }, [events]);

  const handleDelete = async () => {
    if (!token || !selectedEvent) return;
    await deleteEvent(token, selectedEvent, setEvents, setSelectedEvent, setIsDeleteDialogOpen, toast);
  };

  return (
    <div className='space-y-6'>
      {/* Header */}
      <Card className='bg-gradient-to-r from-purple-900 to-pink-900 text-white'>
        <div className='p-6 flex flex-col gap-2'>
          <h2 className='text-2xl font-bold'>Welcome back, Host!</h2>
          <p className='opacity-90'>Manage your events, track status, and create new experiences.</p>
        </div>
      </Card>

      {/* Filters */}
      <div className='flex items-center gap-2 sm:gap-3'>
        {(['all', 'upcoming', 'past'] as FilterType[]).map((f) => (
          <button
            key={f}
            onClick={() => {
              setActiveFilter(f);
              setCurrentPage(1);
            }}
            className={`relative px-4 py-2 rounded-full text-sm font-medium transition-all ring-1 ring-purple-200/60 hover:ring-purple-400/60 ${
              activeFilter === f
                ? 'bg-gradient-to-r from-purple-600 to-pink-600 text-white shadow'
                : 'bg-white text-purple-700 hover:bg-purple-50'
            }`}
          >
            {f === 'all' ? 'All' : f === 'upcoming' ? 'Upcoming' : 'Past'}
          </button>
        ))}
      </div>

      {/* Stats */}
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className='grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4'>
        <StatCard title='Total Events' value={stats.total} change='+0%' icon={Activity} />
        <StatCard title='Approved' value={stats.approved} change='+0%' icon={Check} />
        <StatCard title='Rejected' value={stats.rejected} change='-0%' icon={X} />
      </motion.div>

      {/* Events Grid */}
      {loading ? (
        <Loading />
      ) : events?.length ? (
        <AnimatePresence mode='wait'>
          <motion.div
            key={`${activeFilter}-${currentPage}`}
            initial={{ opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -12 }}
            transition={{ duration: 0.25 }}
            className='grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-6'
          >
            {events.map((event) => (
              <EventCard
                key={event._id}
                event={event}
                role='host'
                actionsMode='menu'
                onEdit={() => {
                  setSelectedEvent(event);
                  setIsEditDialogOpen(true);
                }}
                onDelete={() => {
                  setSelectedEvent(event);
                  setIsDeleteDialogOpen(true);
                }}
              />
            ))}
          </motion.div>
        </AnimatePresence>
      ) : (
        <NotFound message='No events found' />
      )}

      {/* Pagination */}
      {events.length > 0 && totalPages > 1 && (
        <Pagination currentPage={currentPage} totalPages={totalPages} paginate={setCurrentPage} />
      )}

      {/* Floating Create Button -> navigate to /create */}
      <Link href='/create' className='fixed bottom-6 right-6 z-40'>
        <span className='inline-flex items-center gap-2 rounded-full bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white shadow-lg px-5 py-3'>
          <Plus className='h-5 w-5' /> Create Event
        </span>
      </Link>

      {/* Dialogs */}
      <DeleteConfirmationDialog
        open={isDeleteDialogOpen}
        onClose={() => setIsDeleteDialogOpen(false)}
        title='Delete Event'
        description={`Are you sure you want to delete ${selectedEvent?.title}?`}
        onConfirm={handleDelete}
      />
    </div>
  );
};

export default HostDashboard;
